  app.get("/runs/:id/artifacts", async (request, reply) => {
    const id = (request.params as { id: string }).id;
    const run = await deps.runs.get(id);
    if (!run) {
      return reply.code(404).send({ error: { code: "run_not_found", message: `Run not found: ${id}` } });
